import{_ as d,o as a,c as r,ag as l}from"./chunks/framework.DXGyWiRo.js";const i="/media/202509/2025-09-19_151445_8217040.3711939115912446.png",e="/media/202509/2025-09-19_151502_9796950.4740437301972963.png",h="/media/202509/2025-09-19_151521_0026290.07892557370336506.png",q=JSON.parse('{"title":"AC7911B 产品白皮书","description":"","frontmatter":{"title":"AC7911B 产品白皮书"},"headers":[],"relativePath":"hardware/ac7911b/whitepaper.md","filePath":"hardware/ac7911b/whitepaper.md","lastUpdated":null}'),o={name:"hardware/ac7911b/whitepaper.md"};function n(s,t,b,c,u,p){return a(),r("div",null,[...t[0]||(t[0]=[l('<p>概述</p><p>极速交互无屏开发板是一款基于AC7911B集成的性价比极高，且具备完整语音交互功能的一站式解决方案，支持单双麦降噪、离线命令词、在线语音交互、声音复刻、角色定制、超拟人播报、单双工切换、大模型闲聊、音乐点播、故事点播等功能，广泛适用于儿童玩具、智能音箱、语音闹钟等智能硬件的产品开发。 该方案以在线交互为主，建议支持5条以内离线识别命令词，支持在线语音识别和科大讯飞AIUI官方全套技能，支持简单友好的客制化，在客制化方面，该套件支持唤醒词、离线识别命令词和回复语个性化定制以及云端技能的自主配置开发。 若需要产品中单独的离在线能力，请联系商务咨询处理。产品白皮书涵盖开发板的产品规格、产品功能、典型应用场景及电气性能参数，以下为详细内容：</p><h2 id="产品规格" tabindex="-1">产品规格 <a class="header-anchor" href="#产品规格" aria-label="Permalink to &quot;产品规格&quot;">​</a></h2><h3 id="硬件参数" tabindex="-1">硬件参数 <a class="header-anchor" href="#硬件参数" aria-label="Permalink to &quot;硬件参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>类型</strong></td><td><strong>具体参数</strong></td></tr><tr><td>CPU</td><td>320MHz DualCore</td></tr><tr><td>FLASH</td><td>8MB</td></tr><tr><td>SRAM</td><td>512KB</td></tr><tr><td>PSRAM</td><td>2MB</td></tr><tr><td>DVP CAM</td><td>8-bit</td></tr><tr><td>DSP</td><td>回声消除 AEC、噪音消除</td></tr><tr><td>蓝牙</td><td>V5.0 +BR+ EDR +BLE</td></tr><tr><td>Wi-Fi</td><td>802.11 b/g/n 1X1</td></tr><tr><td>麦克风灵敏度</td><td>-27±3dB V/Pa</td></tr></tbody></table><h3 id="开发板实物接口说明" tabindex="-1">开发板实物接口说明 <a class="header-anchor" href="#开发板实物接口说明" aria-label="Permalink to &quot;开发板实物接口说明&quot;">​</a></h3><h4 id="正面图" tabindex="-1">正面图： <a class="header-anchor" href="#正面图" aria-label="Permalink to &quot;正面图：&quot;">​</a></h4><p><img src="'+i+'" alt=""></p><p>图 1 主板正面图</p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>序号</strong></td><td><strong>接口名称</strong></td><td><strong>接口说明</strong></td></tr><tr><td>1</td><td>TYPEC电源接口</td><td>5V电压，既可以给开发板供电，也可以给电池充电，同时可作为固件烧录接口</td></tr><tr><td>2</td><td>电源开关按键</td><td>关闭或开启开发板的供电状态； 灯1：上电亮红灯； 灯2：充电时状态为红灯，充满绿灯。</td></tr><tr><td>3</td><td>模式切换按键</td><td>长按切换单双工，短按打断当次对话</td></tr></tbody></table><h4 id="背面图" tabindex="-1">背面图： <a class="header-anchor" href="#背面图" aria-label="Permalink to &quot;背面图：&quot;">​</a></h4><p><img src="'+e+'" alt=""></p><p>图 2 背面接口图</p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>序号</strong></td><td><strong>接口名称</strong></td><td><strong>接口说明（接口间距1.25mm）</strong></td></tr><tr><td>1</td><td>MIC1口</td><td>2pin驻极体麦接口</td></tr><tr><td>2</td><td>MIC2口</td><td>2pin驻极体麦接口</td></tr><tr><td>3</td><td>喇叭口</td><td>支持接入4欧3W喇叭</td></tr><tr><td>4</td><td>烧录按键</td><td>按下烧录按键后再给主板上电，typeC口可进入烧录模式</td></tr><tr><td>5</td><td>调试串口</td><td>支持串口调试，打日志使用</td></tr><tr><td>6</td><td>通讯串口</td><td>支持串口跟上位机通信（暂未开发）</td></tr><tr><td>7</td><td>GPIO口</td><td>预留3个GPIO口</td></tr><tr><td>8</td><td>2pin电池电源接口</td><td>可接电池供电</td></tr></tbody></table><h3 id="开发板尺寸信息" tabindex="-1">开发板尺寸信息 <a class="header-anchor" href="#开发板尺寸信息" aria-label="Permalink to &quot;开发板尺寸信息&quot;">​</a></h3><p>正面接口尺寸信息：</p><p><img src="'+h+'" alt=""></p><p>图 3 主板尺寸图</p><h2 id="产品功能" tabindex="-1">产品功能 <a class="header-anchor" href="#产品功能" aria-label="Permalink to &quot;产品功能&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>功能</strong></td><td><strong>特性</strong></td></tr><tr><td>回声消除</td><td>回声消除-20dB</td></tr><tr><td>降噪效果</td><td>单麦噪声抑制-10dB 双麦噪声抑制-15dB</td></tr><tr><td>语音唤醒</td><td>安静场景可达97%以上的唤醒成功率 支持自定义唤醒词定制</td></tr><tr><td>离线识别</td><td>支持5条本地指令离线识别</td></tr><tr><td>在线识别</td><td>支持中英文和方言识别 三级VAD识别（提升速度） 情绪识别 流式识别（提升速度） 全双工打断 单双工切换</td></tr><tr><td>语义理解</td><td>提供100多个官方技能 支持自定义技能 支持小星畅聊大模型（专为交互打磨的大模型） 支持符合儿童交互的大模型 支持聚合搜索 实时安全审核、人工审核</td></tr><tr><td>语音合成</td><td>支持多语种和方言合成 提供100多个发音人供选择 支持超拟人合成 支持一句话音色复刻 支持流式合成（提升响应速度）</td></tr><tr><td>TME音乐</td><td>6000万首音乐超大曲库</td></tr></tbody></table><h3 id="语音唤醒" tabindex="-1">语音唤醒 <a class="header-anchor" href="#语音唤醒" aria-label="Permalink to &quot;语音唤醒&quot;">​</a></h3><p>此开发套件唤醒词默认为”小飞小飞”，可以说”小飞小飞”将设备唤醒，然后可以进行语音交互。</p><h3 id="语音识别" tabindex="-1">语音识别 <a class="header-anchor" href="#语音识别" aria-label="Permalink to &quot;语音识别&quot;">​</a></h3><ul><li>支持中英文和方言识别</li><li>三级VAD识别（提升速度）</li><li>情绪识别</li><li>流式识别（提升速度）</li></ul><h3 id="语义理解" tabindex="-1">语义理解 <a class="header-anchor" href="#语义理解" aria-label="Permalink to &quot;语义理解&quot;">​</a></h3><h4 id="多模型调用支持" tabindex="-1">多模型调用支持 <a class="header-anchor" href="#多模型调用支持" aria-label="Permalink to &quot;多模型调用支持&quot;">​</a></h4><h5 id="支持调用专为交互升级的大模型" tabindex="-1">支持调用专为交互升级的大模型 <a class="header-anchor" href="#支持调用专为交互升级的大模型" aria-label="Permalink to &quot;支持调用专为交互升级的大模型&quot;">​</a></h5><ul><li>专为交互场景训练的模型，输出内容更符合交互场景</li><li>耐心倾听</li><li>记忆增强</li><li>情感共鸣</li><li>主动对话</li></ul><h5 id="儿童交互场景打磨的大模型" tabindex="-1">儿童交互场景打磨的大模型 <a class="header-anchor" href="#儿童交互场景打磨的大模型" aria-label="Permalink to &quot;儿童交互场景打磨的大模型&quot;">​</a></h5><ul><li>早教技能（成语接龙、诗词跟读、英语教学…）</li><li>耐心倾听</li><li>童语理解</li><li>正向引导</li><li>安全守护</li><li>兴趣游戏（故事共创…）</li></ul><h5 id="三方开源大模型接入" tabindex="-1">三方开源大模型接入 <a class="header-anchor" href="#三方开源大模型接入" aria-label="Permalink to &quot;三方开源大模型接入&quot;">​</a></h5><ul><li>DeepSeek</li><li>Qwen</li><li>…</li></ul><h4 id="支持精品信源矩阵" tabindex="-1">支持精品信源矩阵 <a class="header-anchor" href="#支持精品信源矩阵" aria-label="Permalink to &quot;支持精品信源矩阵&quot;">​</a></h4><ul><li>10+娱乐生活精品智能体</li><li>4000万首正版音乐</li><li>1200万小时有声内容</li><li>支持通过自然语言进行调用</li></ul><h4 id="支持角色扮演-功能正在调优完善中" tabindex="-1">支持角色扮演（功能正在调优完善中） <a class="header-anchor" href="#支持角色扮演-功能正在调优完善中" aria-label="Permalink to &quot;支持角色扮演（功能正在调优完善中）&quot;">​</a></h4><p>支持扮演角色如下：</p><ol><li>林黛玉角色</li><li>小猪佩奇角色</li><li>蜡笔小新角色</li><li>孙悟空角色</li><li>熊二角色</li><li>甄嬛角色</li><li>乌拉那拉·宜修角色</li><li>沈眉庄角色</li><li>崔槿汐角色</li><li>安陵容角色</li><li>包拯角色</li><li>许仙角色</li><li>小青角色</li><li>白素贞角色</li><li>李逍遥角色</li><li>唐僧角色</li><li>和珅角色</li><li>吴用角色</li><li>宋江角色</li><li>黄蓉角色</li><li>诸葛亮角色</li><li>韦小宝角色</li><li>冷清秋角色</li><li>金燕西角色</li><li>薛宝钗角色</li><li>王熙凤角色</li><li>小燕子角色</li><li>夏紫薇角色</li><li>五阿哥角色</li><li>李李角色</li><li>阿宝角色</li></ol><h3 id="语音合成" tabindex="-1">语音合成 <a class="header-anchor" href="#语音合成" aria-label="Permalink to &quot;语音合成&quot;">​</a></h3><ul><li>支持流式合成和分批输出，占用内存低，速度快</li><li>支持超拟人合成，情感语速可调节</li><li>支持一句话声音复刻</li><li>支持多语种和方言合成</li><li>提供100多个发音人供选择</li></ul><h3 id="安全审核" tabindex="-1">安全审核 <a class="header-anchor" href="#安全审核" aria-label="Permalink to &quot;安全审核&quot;">​</a></h3><ul><li>基础数据安全（讯飞精品安全数据训练大模型）</li><li>实时审核（在线审核模型实时审核输入输出内容）</li><li>人工审核（部分在线判断模糊的内容人工二次审核）</li><li>运营审核（特定行业特定审核运营）</li></ul><h2 id="典型应用场景" tabindex="-1">典型应用场景 <a class="header-anchor" href="#典型应用场景" aria-label="Permalink to &quot;典型应用场景&quot;">​</a></h2><ul><li>智能音箱</li><li>按摩椅</li><li>茶吧机</li><li>取暖桌</li><li>故事机</li><li>儿童玩具</li><li>智能台历</li><li>智能灯具</li><li>智能马桶</li><li>智能台灯</li></ul><h2 id="电气性能参数" tabindex="-1">电气性能参数 <a class="header-anchor" href="#电气性能参数" aria-label="Permalink to &quot;电气性能参数&quot;">​</a></h2><h3 id="关键参数" tabindex="-1">关键参数 <a class="header-anchor" href="#关键参数" aria-label="Permalink to &quot;关键参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>项目</strong></td><td><strong>参数</strong></td></tr><tr><td>麦克风</td><td>Mic.X-6027L200MM2.0-2P</td></tr><tr><td>灵敏度</td><td>-27±3dB</td></tr><tr><td>信噪比</td><td>75dB</td></tr><tr><td>扬声器</td><td>4Ω3W</td></tr><tr><td>PCB 尺寸</td><td>50*50mm</td></tr></tbody></table><h3 id="环境温度" tabindex="-1">环境温度 <a class="header-anchor" href="#环境温度" aria-label="Permalink to &quot;环境温度&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>项目</strong></td><td><strong>参数</strong></td></tr><tr><td>工作温度</td><td>-20°C to 70°C</td></tr><tr><td>存储温度</td><td>-20°C to 70°C</td></tr><tr><td>工作湿度</td><td>10% to 95% 无凝露</td></tr></tbody></table><h3 id="电气参数" tabindex="-1">电气参数 <a class="header-anchor" href="#电气参数" aria-label="Permalink to &quot;电气参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>项目</strong></td><td><strong>最小</strong></td><td><strong>典型</strong></td><td><strong>最大</strong></td></tr><tr><td>工作电压（DC5V）</td><td>4.75V</td><td>5V</td><td>5.25V</td></tr><tr><td>工作电流（DC5V）</td><td>90mA</td><td>120mA</td><td>350mA</td></tr><tr><td>DC 特性 - VIL</td><td>——</td><td>——</td><td>0.8V</td></tr><tr><td>DC 特性 - VIH</td><td>2.0V</td><td>——</td><td>——</td></tr><tr><td>DC 特性 - VOL</td><td>——</td><td>——</td><td>0.4</td></tr><tr><td>DC 特性 - VOH</td><td>2.4</td><td>——</td><td>——</td></tr></tbody></table>',50)])])}const g=d(o,[["render",n]]);export{q as __pageData,g as default};
